# ---------------------------------------------------------------------------
# score.md §4b.1 — Evidence Report Template Data Fields
# ---------------------------------------------------------------------------


class TestEvidenceReportTemplateFields:
    @pytest.fixture(scope="class")
    def fallback_section(self) -> str:
        text = _read(SCORE_FILE)
        start = text.find("### 4b.")
        end = text.find("### 5.")
